# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

from prometheus_client import start_http_server, Summary
from flask import Flask, request

app = Flask(__name__)

# Create a new metric for each unique user-path combination
user_path_metrics = {}

@app.route('/', methods=['GET', 'POST'])
def track_request():
    user_id = request.headers.get('user_id')
    session_id = request.headers.get('session_id')
    full_path = request.path

    # Create a new metric if it doesn't exist
    if (user_id, full_path) not in user_path_metrics:
        user_path_metrics[(user_id, full_path)] = Summary(
            name='user_path_requests',
            documentation=f'Number of requests for user {user_id} on path {full_path}',
            labelnames=['user_id', 'session_id', 'full_path']
        )

    # Increment the metric for the current user-path combination
    user_path_metrics[(user_id, full_path)].labels(user_id, session_id, full_path).inc()

    return 'Request tracked.'

if __name__ == '__main__':
    start_http_server(8080)
    app.run(host='0.0.0.0', port=8080)